// Click to play single sound
if (window.p5Instance) {
  const p = window.p5Instance;

  // Check if mouse is over the cube
  const mouseOver = p.mouseX > this.x - this.width/2 && 
                    p.mouseX < this.x + this.width/2 &&
                    p.mouseY > this.y - this.height/2 && 
                    p.mouseY < this.y + this.height/2;

  // Change color on hover
  if (mouseOver) {
    this.color = '#00ffaa';

    // Play sound on click
    if (p.mouseIsPressed && !this.wasPressed && window.audioEngine && window.audioEngine.initialized) {
      this.playAudio('click-sound', { note: 'C5', duration: '8n' });
      this.wasPressed = true;
    }
  } else {
    this.color = '#00ff00';
  }

  // Reset pressed state when mouse released
  if (!p.mouseIsPressed) {
    this.wasPressed = false;
  }
}

// Click to play mix (chord)
if (window.p5Instance) {
  const p = window.p5Instance;

  // Check if mouse is over the cube
  const mouseOver = p.mouseX > this.x - this.width/2 && 
                    p.mouseX < this.x + this.width/2 &&
                    p.mouseY > this.y - this.height/2 && 
                    p.mouseY < this.y + this.height/2;

  // Change color on hover
  if (mouseOver) {
    this.color = '#ff9944';

    // Play mix on click - plays bass and melody together
    if (p.mouseIsPressed && !this.wasPressed && window.audioEngine && window.audioEngine.initialized) {
      // Play both sounds in the mix simultaneously
      this.playAudio('bass', { note: 'C3', duration: '4n' });
      this.playAudio('melody', { note: 'E4', duration: '4n' });
      this.wasPressed = true;
    }
  } else {
    this.color = '#ff6600';
  }

  // Reset pressed state when mouse released
  if (!p.mouseIsPressed) {
    this.wasPressed = false;
  }
}
